mapper.select:
SELECT
COUNT(DISTINCT su.id) AS schedule_count,
COALESCE(SUM(IFNULL(ast_agg.cnt,0)),0) AS task_total,
COALESCE(SUM(IFNULL(ast_agg.done_cnt,0)),0) AS done_cnt,
COALESCE(SUM(IFNULL(ast_agg.active_cnt,0)),0) AS active_cnt,
COALESCE(SUM(IFNULL(ast_agg.overdue_cnt,0)),0) AS overdue_cnt
FROM app_team_schedule su
LEFT JOIN app_team team_id ON team_id.id=su.team_id
LEFT JOIN (
SELECT CAST(schedule_id AS CHAR) sid,
COUNT(1) cnt,
SUM(CASE WHEN CAST(IFNULL(status,'') AS CHAR)='2' THEN 1 ELSE 0 END) done_cnt,
SUM(CASE WHEN CAST(IFNULL(status,'') AS CHAR) IN ('0','1') THEN 1 ELSE 0 END) active_cnt,
SUM(CASE WHEN CAST(IFNULL(status,'') AS CHAR)='3' THEN 1 ELSE 0 END) overdue_cnt
FROM app_schedule_task
GROUP BY CAST(schedule_id AS CHAR)
) ast_agg ON ast_agg.sid=CAST(su.id AS CHAR)
WHERE 1 = 1
AND CAST(IFNULL(team_id.audit_status,'') AS CHAR)='1'
AND CAST(IFNULL(team_id.status,'') AS CHAR)='1'
AND su.id = #{id}
AND su.team_id = #{team_id}
AND su.title = #{title}
AND su.content = #{content}
AND su.start_time = #{start_time}
AND su.end_time = #{end_time}
AND su.creator_id = #{creator_id}
AND su.leader_user_id = #{leader_user_id}
AND su.visibility_type = #{visibility_type}
AND su.status = #{status}
AND su.create_time = #{create_time}
AND su.update_time = #{update_time}

 AND (
   CAST(su.team_id AS CHAR) in (
     SELECT CAST(t.id AS CHAR) FROM app_team t
     WHERE CAST(t.admin_id AS CHAR)=CAST(#{login_user_id} AS CHAR) OR CAST(t.creator_id AS CHAR)=CAST(#{login_user_id} AS CHAR)
   )
   OR CAST(su.team_id AS CHAR) in (
     SELECT CAST(tu.team_id AS CHAR) FROM app_team_user tu
     WHERE CAST(tu.user_id AS CHAR)=CAST(#{login_user_id} AS CHAR) AND CAST(IFNULL(tu.status,'') AS CHAR)='1'
   )
 )

SELECT
su.id AS id,
IFNULL(NULLIF(TRIM(su.title),''),CONCAT('日程#',CAST(su.id AS CHAR))) AS title,
COALESCE(ast_agg.cnt,0) AS progress_total1,
COALESCE(ast_agg.done_cnt,0) AS progress_done1,
COALESCE(ast_agg.active_cnt,0) AS progress_active1,
COALESCE(ast_agg.overdue_cnt,0) AS progress_overdue1
FROM app_team_schedule su
LEFT JOIN app_team team_id ON team_id.id=su.team_id
LEFT JOIN (
SELECT CAST(schedule_id AS CHAR) sid,
COUNT(1) cnt,
SUM(CASE WHEN CAST(IFNULL(status,'') AS CHAR)='2' THEN 1 ELSE 0 END) done_cnt,
SUM(CASE WHEN CAST(IFNULL(status,'') AS CHAR) IN ('0','1') THEN 1 ELSE 0 END) active_cnt,
SUM(CASE WHEN CAST(IFNULL(status,'') AS CHAR)='3' THEN 1 ELSE 0 END) overdue_cnt
FROM app_schedule_task
GROUP BY CAST(schedule_id AS CHAR)
) ast_agg ON ast_agg.sid=CAST(su.id AS CHAR)
WHERE 1 = 1
AND CAST(IFNULL(team_id.audit_status,'') AS CHAR)='1'
AND CAST(IFNULL(team_id.status,'') AS CHAR)='1'
AND su.id = #{id}
AND su.team_id = #{team_id}
AND su.title = #{title}
AND su.content = #{content}
AND su.start_time = #{start_time}
AND su.end_time = #{end_time}
AND su.creator_id = #{creator_id}
AND su.leader_user_id = #{leader_user_id}
AND su.visibility_type = #{visibility_type}
AND su.status = #{status}
AND su.create_time = #{create_time}
AND su.update_time = #{update_time}

 AND (
   CAST(su.team_id AS CHAR) in (
     SELECT CAST(t.id AS CHAR) FROM app_team t
     WHERE CAST(t.admin_id AS CHAR)=CAST(#{login_user_id} AS CHAR) OR CAST(t.creator_id AS CHAR)=CAST(#{login_user_id} AS CHAR)
   )
   OR CAST(su.team_id AS CHAR) in (
     SELECT CAST(tu.team_id AS CHAR) FROM app_team_user tu
     WHERE CAST(tu.user_id AS CHAR)=CAST(#{login_user_id} AS CHAR) AND CAST(IFNULL(tu.status,'') AS CHAR)='1'
   )
 )

ORDER BY
CASE WHEN COALESCE(ast_agg.cnt,0)=0 THEN 101 ELSE COALESCE(ast_agg.done_cnt,0)*100.0/ast_agg.cnt END ASC,
su.id DESC

LIMIT #{limit_size}
